"""
Parser for Codex JSONL conversation transcripts.

Codex archives each session as append-only JSONL. The fixture in tests shows a
top-level `session_meta` record plus `response_item` / `event_msg` records.
This module extracts the session metadata, searchable text, and structured
turns used by the search index and viewer.
"""

from __future__ import annotations

import json
import re
import sys
from collections import Counter
from pathlib import Path
from typing import Optional

_INPUT_TEXT_TYPES = {"input_text", "text"}
_OUTPUT_TEXT_TYPES = {"output_text", "text"}


def parse_jsonl(filepath: Path) -> list[dict]:
    lines = []
    with open(filepath, "r", encoding="utf-8") as f:
        for i, raw in enumerate(f, 1):
            raw = raw.strip()
            if not raw:
                continue
            try:
                lines.append(json.loads(raw))
            except json.JSONDecodeError as e:
                print(f"Warning: {filepath}:{i}: malformed JSON: {e}", file=sys.stderr)
    return lines


def _blocks(item: dict) -> list[dict]:
    payload = item.get("payload") or {}
    if payload.get("type") == "message":
        content = payload.get("content") or []
        return content if isinstance(content, list) else []
    return []


def _message_role(item: dict) -> str:
    payload = item.get("payload") or {}
    return payload.get("role") or ""


def _extract_text_from_blocks(blocks: list[dict], allowed: set[str]) -> list[str]:
    out = []
    for block in blocks:
        if block.get("type") in allowed and block.get("text"):
            out.append(block["text"])
    return out


def _first_user_prompt(lines: list[dict]) -> Optional[str]:
    for item in lines:
        if item.get("type") != "response_item":
            continue
        if _message_role(item) != "user":
            continue
        texts = _extract_text_from_blocks(_blocks(item), _INPUT_TEXT_TYPES)
        for text in texts:
            if text.strip():
                return text
    return None


def _last_timestamped_line(lines: list[dict]) -> Optional[dict]:
    for item in reversed(lines):
        if item.get("timestamp"):
            return item
    return None


def extract_model(lines: list[dict]) -> str:
    counts: Counter[str] = Counter()
    for item in lines:
        if item.get("type") == "session_meta":
            model = (item.get("payload") or {}).get("model")
            if model:
                counts[model] += 1
        elif item.get("type") == "turn_context":
            model = (item.get("payload") or {}).get("model")
            if model:
                counts[model] += 1
    return counts.most_common(1)[0][0] if counts else ""


def extract_session_metadata(lines: list[dict]) -> dict:
    session_id = ""
    cwd = ""
    first = None
    last = _last_timestamped_line(lines)

    for item in lines:
        if item.get("type") == "session_meta":
            payload = item.get("payload") or {}
            session_id = session_id or payload.get("id", "")
            cwd = cwd or payload.get("cwd", "")
            first = first or item
        elif item.get("type") == "turn_context":
            payload = item.get("payload") or {}
            cwd = cwd or payload.get("cwd", "")
            first = first or item

    created_at = (first or {}).get("timestamp", "")
    updated_at = (last or {}).get("timestamp", created_at)

    return {
        "session_id": session_id,
        "cwd": cwd,
        "git_branch": "",
        "created_at": created_at,
        "updated_at": updated_at,
        "name": _first_user_prompt(lines) or "(untitled)",
        "model": extract_model(lines),
    }


def extract_searchable_text(lines: list[dict]) -> list[str]:
    texts = []
    for item in lines:
        if item.get("type") != "response_item":
            continue
        role = _message_role(item)
        blocks = _blocks(item)
        if role == "user":
            texts.extend(_extract_text_from_blocks(blocks, _INPUT_TEXT_TYPES))
        elif role == "assistant":
            texts.extend(_extract_text_from_blocks(blocks, _OUTPUT_TEXT_TYPES))
    return [t for t in texts if t.strip()]


def count_tool_uses(lines: list[dict]) -> "Counter[str]":
    counts: Counter[str] = Counter()
    for item in lines:
        if item.get("type") != "response_item" or _message_role(item) != "assistant":
            continue
        for block in _blocks(item):
            if block.get("type") == "tool_use" and block.get("name"):
                counts[block["name"]] += 1
    return counts


def extract_conversation_turns(lines: list[dict]) -> list[dict]:
    turns = []
    for item in lines:
        if item.get("type") != "response_item":
            continue
        role = _message_role(item)
        if role not in {"user", "assistant"}:
            continue
        blocks = _blocks(item)
        if role == "user":
            text = "\n\n".join(_extract_text_from_blocks(blocks, _INPUT_TEXT_TYPES)).strip()
            if text:
                turns.append({
                    "role": "user",
                    "timestamp": item.get("timestamp", ""),
                    "content": text,
                    "tool_uses": [],
                })
        else:
            text = "\n\n".join(_extract_text_from_blocks(blocks, _OUTPUT_TEXT_TYPES)).strip()
            tools = []
            for block in blocks:
                if block.get("type") == "tool_use" and block.get("name") and block["name"] not in tools:
                    tools.append(block["name"])
            if text or tools:
                turns.append({
                    "role": "assistant",
                    "timestamp": item.get("timestamp", ""),
                    "content": text,
                    "tool_uses": tools,
                })
    return turns


def find_session_file(codex_data_dir: Path, session_id: str) -> Optional[Path]:
    if not codex_data_dir.exists():
        return None
    for path in codex_data_dir.rglob("*.jsonl"):
        if path.name == f"{session_id}.jsonl":
            return path
    return None

